#!/usr/bin/env tsx

/**
 * Test script to focus only on electronics assessment
 */

import { assessDamageEnhanced } from '@/features/cases/services/ai-assessment-enhanced.service';

async function testElectronicsOnly() {
  console.log('📱 Testing Electronics Assessment Only...\n');

  try {
    const assessment = await assessDamageEnhanced({
      photos: [
        'data:image/jpeg;base64,',
        'data:image/jpeg;base64,',
        'data:image/jpeg;base64,'
      ],
      universalItemInfo: {
        type: 'electronics',
        brand: 'Apple',
        model: 'iPhone 14 Pro',
        condition: 'Foreign Used (Tokunbo)',
        storageCapacity: '256GB',
        batteryHealth: 85,
        age: 2
      }
    });

    console.log('Assessment Results:');
    console.log(`Confidence Score: ${assessment.confidenceScore}%`);
    console.log(`Market Value: ₦${assessment.marketValue.toLocaleString()}`);
    console.log(`Salvage Value: ₦${assessment.estimatedSalvageValue.toLocaleString()}`);
    
    if (assessment.confidenceScore > 100) {
      console.log('❌ ISSUE: Confidence score is too high!');
    } else {
      console.log('✅ Confidence score is within expected range');
    }

  } catch (error) {
    console.error('❌ Test failed:', error);
  }
}

testElectronicsOnly().catch(console.error);